import React from "react";

const Cover = () => {
    return (
        <div className="ui grid">
            <div className="ui segment grid-top" style={{width:"50vw",height:"50vh",backgroundColor:"red"}}></div>
            <div className="ui segment grid-bottom" style={{width:"50vw",height:"50vh",backgroundColor:"blue"}}></div>
        </div>
    )
};
export default Cover;
